&lt;p&gt;&lt;span style=&quot;&quot;&gt;Similarly,&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;20&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;∶&amp;nbsp;?&amp;nbsp;&amp;rarr; (20)&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;+ 10&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;rArr;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;400&amp;nbsp;+ 10 = 410&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;And,&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;32&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;∶&amp;nbsp;1034&amp;nbsp;&amp;rarr; (32)&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;+ 10&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;rArr;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;1024&amp;nbsp;+ 10 = 1034&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;Hence, &lt;strong&gt;&amp;quot;Option 1&amp;quot; &lt;/strong&gt;is the &lt;strong&gt;correct answer.&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;<br><br><p><strong>तर्क: (पहली संख्या)<sup>2</sup> + 10 = दूसरी संख्या</strong></p>

<p><span style="">12 ∶ 154 &rarr; (12)<sup>2</sup> + 10 &rArr; 144 + 10 = 154</span></p>

